"""calus: protocol-abuse  (38 patterns)"""

PATTERNS = [
    ('(?i)(?:jsonrpc|mcp\\s*message).{0,40}(?:override|override|inject|alter)', 'medium', 'mcp-protocol-abuse-jsonrpc-manipulation: Detects patterns that manipulate JSON-RPC messages to inject unauthorized commands. Based on Piazza'),
    ('(?i)"method"\\s*:\\s*"(?:tools/call|resources/read)".{0,60}"params"\\s*:\\s*\\{', 'low', 'mcp-protocol-abuse-jsonrpc-manipulation: Detects manipulation of JSON-RPC messages in MCP to inject unintended commands or parameters (Secti'),
    ('(?i)"arguments"\\s*:\\s*\\{.{0,100}}(?:[^}]*"__proto__"\\s*:)', 'low', 'mcp-protocol-abuse-jsonrpc-manipulation: Detects manipulation of JSON-RPC messages in MCP to inject unintended commands or parameters (Secti'),
    ('(?i)"method"\\s*:\\s*"(?:tools\\/call|resources\\/read|prompts\\/get)"', 'low', 'mcp-protocol-abuse-jsonrpc-crafted: Detects crafted JSON-RPC messages that deviate from standard structure, used in protocol abuse attacks.'),
    ('(?i)"params"\\s*:\\s*\\{[^}]{0,200}(?:\'|")(?:id|input|arguments)(?:\'|"):', 'low', 'mcp-protocol-abuse-jsonrpc-crafted: Detects crafted JSON-RPC messages that deviate from standard structure, used in protocol abuse attacks.'),
    ('(?i)\x08name_collision\x08.{0,40}\x08mcp\x08', 'low', 'mcp-protocol-abuse-name-collision-scanner: Detects potential protocol abuse via name collisions in MCP server registries, leading to command'),
    ('(?i)\x08confused_deputy\x08.{0,40}\x08mcp\x08', 'low', 'mcp-protocol-abuse-name-collision-scanner: Detects potential protocol abuse via name collisions in MCP server registries, leading to command'),
    ('(?i)"method"\\s*:\\s*"\\w+".{0,100}"params"\\s*:\\s*\\{.{0,100}"command"\\s*:\\s*["\']\\w+', 'low', 'mcp-protocol-abuse-jsonrpc: Detects crafted JSON-RPC messages that encode unintended commands or parameter manipulation.'),
    ('(?i)"id"\\s*:\\s*\\d+.{0,100}"method"\\s*:\\s*"execute".{0,100}"params"\\s*:\\s*\\{.{0,100}"payload"\\s*:\\s*["\']', 'low', 'mcp-protocol-abuse-jsonrpc: Detects crafted JSON-RPC messages that encode unintended commands or parameter manipulation.'),
    ('(?i)[\'"]method[\'"].{0,40}[\'"](?:tools/list|resources/list|prompts/get)[\'"].{0,40}(?:[\'"]id[\'"].{0,40}[\'"][\\d]|[\'"]params[\'"].{0,40}\\{)', 'high', 'mcp-protocol-abuse-jsonrpc-manipulation: Detects manipulation of MCP JSON-RPC messages to inject unauthorized commands or parameters.'),
    ('(?i)\\bset\\s*\\(.{0,40}[\'"]method[\'"].{0,40}[\'"]tools', 'high', 'mcp-protocol-abuse-jsonrpc-manipulation: Detects manipulation of MCP JSON-RPC messages to inject unauthorized commands or parameters.'),
    ('(?i)jsonrpc.{0,100}(?:method|params).{0,100}(?:collision|override|shadow|spoof)', 'low', 'mcp-protocol-abuse-name-collision-jsonrpc: Detects crafted JSON-RPC messages that exploit namespace collisions to confuse tool dispatch, as '),
    ('(?i)"method"\\s*:\\s*[\'"](?:collide|override|shadow|duplicate)[\\.\\w]*[\'"]', 'low', 'mcp-protocol-abuse-name-collision-jsonrpc: Detects crafted JSON-RPC messages that exploit namespace collisions to confuse tool dispatch, as '),
    ('(?i)(?:from|import)\\s+.{0,40}\\b(name_collision|collision_attack)\\b', 'low', 'mcp-protocol-abuse-name-collision-jsonrpc: Detects crafted JSON-RPC messages that exploit namespace collisions to confuse tool dispatch, as '),
    ('(?i)(?:crafted|malicious|manipulated)\\s+(?:MCP|JSON[-_]?RPC)\\s+(?:message|request|response)', 'low', 'mcp-protocol-abuse-message-manipulation: Detects abuse of MCP JSON-RPC messages where attackers craft messages that cause unauthorized actio'),
    ('(?i)(?:protocol\\s+abuse|message\\s+injection)\\s+(?:tool\\s+call|resource\\s+access)', 'low', 'mcp-protocol-abuse-message-manipulation: Detects abuse of MCP JSON-RPC messages where attackers craft messages that cause unauthorized actio'),
    ('(?i)(?:unauthorized\\s+operation|command\\s+overlap)\\s+(?:JSON[-_]?RPC|MCP)', 'low', 'mcp-protocol-abuse-message-manipulation: Detects abuse of MCP JSON-RPC messages where attackers craft messages that cause unauthorized actio'),
    ('(?i)(?:parameter\\s+injection|message\\s+spoof)\\s+(?:tool|resource)', 'low', 'mcp-protocol-abuse-message-manipulation: Detects abuse of MCP JSON-RPC messages where attackers craft messages that cause unauthorized actio'),
    ('(?i)\\b(?:method|params|id)\\s*[:=]\\s*[\'"]\\s*(?:malicious|hidden|override|spoof)', 'low', 'mcp-protocol-abuse-jsonrpc-manipulation: Detects patterns that manipulate MCP JSON-RPC messages, e.g., overwriting method, params, or id to '),
    ('(?i)command_overlap\\s*=\\s*[\\"\']malicious', 'medium', 'mcp-protocol-abuse-command-overlap: Detects namespace collisions or command overlap in MCP registries, as described by Shapira 2025.'),
    ('(?i)register_command\\s*\\(\\s*[\\"\']trusted-name', 'medium', 'mcp-protocol-abuse-command-overlap: Detects namespace collisions or command overlap in MCP registries, as described by Shapira 2025.'),
    ('(?i)json\\.(?:loads|dumps)\\s*\\(\\s*[^)]*\\bmethod\\s*[\'"]\\s*:\\s*[\'"]tools/call[\'"]', 'high', 'mcp-protocol-abuse-jsonrpc-manipulation: Detects MCP code that manipulates JSON-RPC messages to inject unauthorized parameters or commands, '),
    ('(?i)params\\s*=\\s*{.{0,60}\\barguments\\b.{0,60}\\bcmd\\b', 'high', 'mcp-protocol-abuse-jsonrpc-manipulation: Detects MCP code that manipulates JSON-RPC messages to inject unauthorized parameters or commands, '),
    ('(?i)"jsonrpc"\\s*:\\s*"2.0".{0,60}"method"\\s*:\\s*"[^"]*inject', 'high', 'mcp-protocol-abuse-jsonrpc-manipulation: Detects MCP code that manipulates JSON-RPC messages to inject unauthorized parameters or commands, '),
    ('(?i)(?:namespace|registry).{0,40}(?:collision|overlap|conflict)', 'low', 'mcp-protocol-abuse-name-collision: Detects namespace collisions or command overlap in MCP registries enabling confused-deputy attacks.'),
    ('(?i)(?:tool|command).{0,40}(?:name|alias).{0,40}(?:overlap|conflict)', 'low', 'mcp-protocol-abuse-name-collision: Detects namespace collisions or command overlap in MCP registries enabling confused-deputy attacks.'),
    ('(?i)(?:duplicate|identical|collide).{0,40}(?:tool|resource|server).{0,40}(?:name|id)', 'low', 'mcp-protocol-abuse-name-collision: Detects name collisions or command overlap in MCP registries that enable confused-deputy attacks.'),
    ('(?i)json[-_]?rpc\\b.{0,40}\\b(?:inject|manip|forg|spoof|tamper)\\b', 'low', 'mcp-protocol-abuse-jsonrpc-manipulation: Detects manipulation of MCP JSON-RPC messages to inject unauthorized commands, parameters, or tool '),
    ('(?i)(?:method|params)\\s*[\'"]?[\'"]?\\s*:\\s*[\'"]?[\'"]?\\s*(?:[^,{}]{30,200})\\bignore\\b.{0,40}\\bpolicy', 'low', 'mcp-protocol-abuse-jsonrpc-manipulation: Detects manipulation of MCP JSON-RPC messages to inject unauthorized commands, parameters, or tool '),
    ('(?i)(?:register|add)_tool\\s*\\(\\s*[\'"](?:delete|admin|system|root|sudo)[\'"]', 'high', 'mcp-protocol-abuse-name-collision: Detects name collision risks in MCP registries that enable protocol abuse (Shapira 2025; Hou et al. 2025)'),
    ('(?i)tool_name\\s*[:=]\\s*[\'"](?:delete|admin|root|system)[\'"]', 'high', 'mcp-protocol-abuse-name-collision: Detects name collision risks in MCP registries that enable protocol abuse (Shapira 2025; Hou et al. 2025)'),
    ('(?i)namespace\\s*(?:collision|squatting|shadowing)', 'high', 'mcp-protocol-abuse-name-collision: Detects name collision risks in MCP registries that enable protocol abuse (Shapira 2025; Hou et al. 2025)'),
    ('(?i)\\b(?:tools/list|resources/list|prompts/get)\\b.{0,40}\\b(?:malformed|crafted|modified|spoofed)\\b', 'low', 'mcp-protocol-abuse-jsonrpc-manipulation: Detects crafted JSON-RPC messages that exploit MCP protocol to manipulate tools or Resources, as de'),
    ('(?i)"name"\\s*:\\s*"(?:read|write|delete|exec|run|list|get|set)"', 'high', 'mcp-protocol-abuse-namespace-collision: Detects potential namespace collisions in MCP tool registries where multiple tools share the same na'),
    ('(?i)tool_declarations[\\s\\S]{0,200}\\bname\\b[\\s\\S]{0,200}\\bname\\b', 'high', 'mcp-protocol-abuse-namespace-collision: Detects potential namespace collisions in MCP tool registries where multiple tools share the same na'),
    ('(?i)"method":.{0,80}"(?:tools|resources|prompts)".{0,80}"params".{0,80}"(?:inject|override|delete)', 'low', 'mcp-protocol-abuse-jsonrpc-manipulation: Detects protocol abuse via crafted MCP JSON-RPC messages encoding unintended commands.'),
    ('(?i)"jsonrpc".{0,80}"2.0".{0,100}(?:malicious|exec|system|command)', 'low', 'mcp-protocol-abuse-jsonrpc-manipulation: Detects protocol abuse via crafted MCP JSON-RPC messages encoding unintended commands.'),
    ('(?i)(?:json.?rpc|rpc).{0,20}(?:manipul|inject|corrupt|override).{0,30}(?:attack|exploit|malicious|inject|payload|bypass|jailbreak|poison|adversar|backdoor|trigger)', 'low', 'mcp-protocol-abuse-jsonrpc-manipulation: Detects manipulated JSON-RPC messages that bypass protocol checks (Piazza 2025; Hou et al. 2025).'),
]